// NetworkService.java
import android.util.Log;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;

public class NetworkService {
    private static final String TAG = "NetworkService";
    private static final String API_BASE_URL = "http://api.bankingapp.com";
    
    public String sendTransaction(String accountNumber, String pin, double amount, String type) {
        try {
            URL url = new URL(API_BASE_URL + "/transaction");
            HttpURLConnection conn = (HttpURLConnection) url.openConnection();
            conn.setRequestMethod("POST");
            conn.setDoOutput(true);
            
            String jsonData = "{\"account\":\"" + accountNumber + "\",\"pin\":\"" + pin + 
                            "\",\"amount\":" + amount + ",\"type\":\"" + type + "\"}";
            
            OutputStream os = conn.getOutputStream();
            os.write(jsonData.getBytes());
            os.flush();
            
            BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()));
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = br.readLine()) != null) {
                response.append(line);
            }
            
            br.close();
            conn.disconnect();
            
            return response.toString();
        } catch (Exception e) {
            Log.e(TAG, "Network error: " + e.getMessage());
            return null;
        }
    }
}